import osimport utils_study study = utils_study.Studyutils = utils_study.Utils()import utils_preprocessing_analysispreprocess_analyse = utils_preprocessing_analysis.OPM_Pipeline(incl_report=False)# =============================================================================# Parameters # =============================================================================input_folder = 'processed_filtered'output_folder = 'preprocessing_routine_2'task = 'oddballTones'# Inser the path to your project folder# root_data_path = '/Users/a.pesquita@bham.ac.uk/Documents/GitHub/babypyopm/Untitled'root_data_path = '/Users/b.pomiechowska@bham.ac.uk/Documents/GitHub/babypyopm/'path_data  = os.path.join(root_data_path,'data')# =============================================================================# Set up # =============================================================================# Get paths to all subfolderspaths = utils.get_paths(root_data_path)# Define the template for generating the filename for raw FIF data filesbasename = '{subj}/{input_folder}/{sub-subj}_file-{task}_filtered_01_40.fif'# Find FIF files that correspond to the template defined abovedataset = study(os.path.join(paths.data, basename)) # List all folders / subjects in '~/data'subjects = [f for f in os.listdir(paths.data) if os.path.isdir(os.path.join(paths.data, f))]print(subjects)subjects = ['sub-107']subj = subjects[0]#%% ----------------------------------------------# Load datasetsdata = preprocess_analyse.load_data(dataset, subjects,paths.data,input_folder,task)aux = data[0]aux.plot(    block=True,    theme="light",    show_scrollbars=True,    duration=10,    start=0,    n_channels=len(aux.ch_names),    #3ArithmeticErrorshow_scalebars=True,    scalings=dict(mag=1e-12, ref_meg=1e-12, stim=1),    title=subjects[0],    show_options=True,    events=None)path_data_file = os.path.join(path_data, subj,'preprocessing_routine_2',f"{subj}_manual_clean.fif")# Create directory if it doesn't existpath_data_subj = os.path.join(path_data, path_data, subj,'preprocessing_routine_2')os.makedirs(path_data_subj, exist_ok=True)aux.save(path_data_file, overwrite=True)import mneraw = mne.io.read_raw_fif(    "/Users/b.pomiechowska@bham.ac.uk/Documents/GitHub/babypyopm/data/sub-107/preprocessing_routine_2/sub-107_manual_clean.fif",    preload=True)#fig.fake_keypress("a")  # Simulates user pressing 'a' on the keyboard.#manual_inspect_data = [preprocess_analyse.run_manual_inspect(d) for d in data]# Save fif files with event info#[utils.save_fif_path(d, task, output_folder, paths.data, output_folder) for d in ica_data]